 5→export type { PolicyTraceEntry } from "../policy/types";
 6→
 7→// --- Intent Status (state machine states) ---
 8→
 9→export type IntentStatus =
10→  | "draft"
11→  | "pending_auth"
12→  | "pending_veto"
13→  | "authorized"
14→  | "executing"
15→  | "completed"
16→  | "vetoed"
17→  | "failed";
18→
19→// --- Action Specification ---
20→
21→export type ActionSpec = {
22→  provider: string;
23→  action: string;
24→  params?: Record<string, unknown>;
25→};
26→
27→// --- Budget Limit ---
28→
29→export type BudgetLimit = {
30→  amount: number;
31→  currency: string;
32→};
33→
34→// --- Evaluation Result ---
35→
36→export type EvaluationResult = {
37→  decision: "APPROVE" | "REJECT";
38→  risk_score: number;
39→  reason: string;
40→  reasoning?: string;
41→};
42→
43→// --- Routing Decision (discriminated union) ---
44→
45→export type RoutingDecision =
46→  | { route: "auto_approve" }
47→  | { route: "veto_window"; expires_at: Date }
48→  | { route: "reject"; reason: string };
49→
50→// --- Intent Record ---
51→
52→export type IntentRecord = {
53→  id: RecordId<"intent", string>;
54→  goal: string;
55→  reasoning: string;
56→  status: IntentStatus;
57→  priority: number;
58→  action_spec: ActionSpec;
59→  budget_limit?: BudgetLimit;
60→  evaluation?: EvaluationResult & {
61→    evaluated_at: Date;
62→    policy_only: boolean;
63→    policy_trace?: PolicyTraceEntry[];
64→    human_veto_required?: boolean;
65→  };
66→  veto_expires_at?: Date;
67→  veto_reason?: string;
68→  error_reason?: string;
69→  authorization_details?: BrainAction[];
70→  dpop_jwk_thumbprint?: string;
71→  token_issued_at?: Date;
72→  token_expires_at?: Date;
73→  embedding?: number[];
74→  trace_id: RecordId<"trace", string>;
75→  requester: RecordId<"identity", string>;
76→  workspace: RecordId<"workspace", string>;
77→  created_at: Date;
78→  updated_at?: Date;
