 1→import type { EvaluationResult, RoutingDecision } from "./types";
 2→
 3→const DEFAULT_AUTO_APPROVE_THRESHOLD = 30;
 4→const DEFAULT_VETO_WINDOW_MINUTES = 30;
 5→
 6→type RiskRouterOptions = {
 7→  autoApproveThreshold?: number;
 8→  vetoWindowMinutes?: number;
 9→  humanVetoRequired?: boolean;
10→};
11→
12→export function routeByRisk(
13→  evaluation: EvaluationResult,
14→  options?: RiskRouterOptions,
15→): RoutingDecision {
16→  if (evaluation.decision === "REJECT") {
17→    return { route: "reject", reason: evaluation.reason };
18→  }
19→
20→  const threshold = options?.autoApproveThreshold ?? DEFAULT_AUTO_APPROVE_THRESHOLD;
21→  const vetoMinutes = options?.vetoWindowMinutes ?? DEFAULT_VETO_WINDOW_MINUTES;
22→
23→  const now = Date.now();
24→
25→  // Policy human_veto_required forces veto_window regardless of risk score
26→  if (options?.humanVetoRequired) {
27→    return { route: "veto_window", expires_at: new Date(now + vetoMinutes * 60 * 1000) };
28→  }
29→
30→  if (evaluation.risk_score <= threshold) {
31→    return { route: "auto_approve" };
32→  }
33→
34→  const expiresAt = new Date(now + vetoMinutes * 60 * 1000);
35→
36→  return { route: "veto_window", expires_at: expiresAt };
37→}
