  1→import { RecordId } from "surrealdb";
  2→import { jsonError, jsonResponse } from "../http/response";
  3→import { updateIntentStatus, listPendingIntents, getIntentById } from "./intent-queries";
  4→import { evaluatePendingIntent } from "./intent-evaluation";
  5→import { renderConsentDisplay, validateTighterBounds } from "../oauth/consent-renderer";
  6→import type { ServerDependencies } from "../runtime/types";
  7→import type { IntentRecord } from "./types";
  8→import type { BrainAction } from "../oauth/types";
  9→import { log } from "../telemetry/logger";
 10→
 11→// --- Route Handler Types ---
 12→
 13→type IntentRouteHandlers = {
 14→  handleEvaluate: (intentId: string, request: Request) => Promise<Response>;
 15→  handleVeto: (workspaceId: string, intentId: string, request: Request) => Promise<Response>;
 16→  handleListPending: (workspaceId: string) => Promise<Response>;
 17→  handleConsent: (workspaceId: string, intentId: string) => Promise<Response>;
 18→  handleApprove: (workspaceId: string, intentId: string) => Promise<Response>;
 19→  handleConstrain: (workspaceId: string, intentId: string, request: Request) => Promise<Response>;
 20→};
 21→
 22→// --- Factory ---
 23→
 24→export function createIntentRouteHandlers(deps: ServerDependencies): IntentRouteHandlers {
 25→  const { surreal } = deps;
 26→
 27→  const handleEvaluate = async (intentId: string, request: Request): Promise<Response> => {
 28→    // Called by SurrealQL EVENT via http::post - receives full intent record as body
 29→    let body: IntentRecord | undefined;
 30→    try {
 31→      body = await request.json() as IntentRecord;
 32→    } catch {
 33→      body = undefined;
 34→    }
 35→
 36→    const bodyIntentId = body && typeof body.id === "object" && body.id !== undefined
 37→      ? (body.id.id as string)
 38→      : undefined;
 39→
 40→    if (bodyIntentId && bodyIntentId !== intentId) {
 41→      return jsonError("Intent ID mismatch between path and payload", 400);
 42→    }
 43→
 44→    if (!body) {
 45→      return jsonError("Invalid JSON body", 400);
 46→    }
 47→
 48→    if (!body.requester) {
 49→      return jsonError("Missing requester in intent body", 400);
 50→    }
 51→
 52→    log.info("intent.evaluate.received", "Evaluate endpoint received intent", {
 53→      intentId,
 54→      status: body.status,
 55→      goal: body.goal,
 56→    });
 57→
 58→    // Idempotency guard: only process intents in pending_auth status
 59→    if (body.status !== "pending_auth") {
 60→      log.info("intent.evaluate.skipped", "Intent not in pending_auth status", {
 61→        intentId,
 62→        currentStatus: body.status,
 63→      });
 64→      return jsonError(`Intent is in '${body.status}' status, expected 'pending_auth'`, 409);
 65→    }
 66→
 67→    try {
 68→      const evaluation = await evaluatePendingIntent(
 69→        intentId,
 70→        {
 71→          surreal,
 72→          extractionModel: deps.extractionModel,
 73→        },
 74→        { intent: body },
 75→      );
 76→      if (!evaluation.ok) {
 77→        return jsonError(evaluation.error, evaluation.httpStatus);
 78→      }
 79→
 80→      const response = {
 81→        intentId,
 82→        status: evaluation.value.status,
 83→        evaluation: evaluation.value.evaluation,
 84→        ...(evaluation.value.vetoExpiresAt
 85→          ? { veto_expires_at: evaluation.value.vetoExpiresAt.toISOString() }
 86→          : {}),
 87→      };
 88→
 89→      log.info("intent.evaluate.completed", "Intent evaluation completed", {
 90→        intentId,
 91→        status: evaluation.value.status,
 92→      });
 93→
 94→      return jsonResponse(response, 200);
 95→    } catch (error) {
 96→      log.error("intent.evaluate.error", "Intent evaluation pipeline failed", error, {
 97→        intentId,
 98→      });
 99→      return jsonError("Internal evaluation error", 500);
100→    }
101→  };
102→
103→  const handleVeto = async (
104→    workspaceId: string,
105→    intentId: string,
106→    request: Request,
107→  ): Promise<Response> => {
108→    let body: { reason: string };
109→    try {
110→      body = await request.json() as { reason: string };
111→    } catch {
112→      return jsonError("Invalid JSON body", 400);
113→    }
114→
115→    if (!body.reason || typeof body.reason !== "string" || body.reason.trim().length === 0) {
116→      return jsonError("reason is required", 400);
117→    }
118→
119→    const result = await updateIntentStatus(surreal, intentId, "vetoed", {
120→      veto_reason: body.reason.trim(),
121→    });
122→
123→    if (!result.ok) {
124→      log.error("intent.veto.failed", "Failed to veto intent", new Error(result.error), {
125→        intentId,
126→        workspaceId,
127→      });
128→      return jsonError(result.error, 409);
129→    }
130→
131→    log.info("intent.vetoed", "Intent vetoed by user", {
132→      intentId,
133→      workspaceId,
134→      reason: body.reason.trim(),
135→    });
136→
137→    return jsonResponse({
138→      intentId,
139→      status: "vetoed",
140→    }, 200);
141→  };
142→
143→  const handleListPending = async (workspaceId: string): Promise<Response> => {
144→    const intents = await listPendingIntents(surreal, workspaceId);
145→
146→    return jsonResponse({
147→      intents: intents.map((intent) => ({
148→        id: intent.id.id as string,
149→        goal: intent.goal,
150→        reasoning: intent.reasoning,
151→        priority: intent.priority,
152→        action_spec: intent.action_spec,
153→        veto_expires_at: intent.veto_expires_at,
154→        created_at: intent.created_at,
155→      })),
156→    }, 200);
157→  };
158→
159→  const handleConsent = async (
160→    _workspaceId: string,
161→    intentId: string,
162→  ): Promise<Response> => {
163→    const intent = await getIntentById(surreal, intentId);
164→    if (!intent) {
165→      return jsonError("Intent not found", 404);
166→    }
167→
168→    // Only pending_veto intents have consent display
169→    if (intent.status !== "pending_veto") {
170→      return jsonError(`Intent is in '${intent.status}' status, expected 'pending_veto'`, 409);
171→    }
172→
173→    const authDetails = intent.authorization_details ?? [];
174→    const firstAction = authDetails[0];
175→
176→    const consentDisplay = firstAction
177→      ? renderConsentDisplay(firstAction)
178→      : { action_display: "Unknown", resource_display: "Unknown" };
179→
180→    return jsonResponse({
181→      ...consentDisplay,
182→      risk_score: intent.evaluation?.risk_score ?? 0,
183→      reasoning: intent.evaluation?.reason ?? "",
184→      expires_at: intent.veto_expires_at
185→        ? (intent.veto_expires_at instanceof Date
186→          ? intent.veto_expires_at.toISOString()
187→          : String(intent.veto_expires_at))
188→        : "",
189→    }, 200);
190→  };
191→
192→  const handleApprove = async (
193→    workspaceId: string,
194→    intentId: string,
195→  ): Promise<Response> => {
196→    const result = await updateIntentStatus(surreal, intentId, "authorized");
197→
198→    if (!result.ok) {
199→      log.error("intent.approve.failed", "Failed to approve intent", new Error(result.error), {
200→        intentId,
201→        workspaceId,
202→      });
203→      return jsonError(result.error, 409);
204→    }
205→
206→    log.info("intent.approved", "Intent approved by human", {
207→      intentId,
208→      workspaceId,
209→    });
210→
211→    return jsonResponse({
212→      intentId,
213→      status: "authorized",
214→    }, 200);
215→  };
216→
217→  const handleConstrain = async (
218→    workspaceId: string,
219→    intentId: string,
220→    request: Request,
221→  ): Promise<Response> => {
222→    let body: { constrained_authorization_details: BrainAction[] };
223→    try {
224→      body = await request.json() as { constrained_authorization_details: BrainAction[] };
225→    } catch {
226→      return jsonError("Invalid JSON body", 400);
227→    }
228→
229→    if (!body.constrained_authorization_details || !Array.isArray(body.constrained_authorization_details)) {
230→      return jsonError("constrained_authorization_details is required", 400);
231→    }
232→
233→    const intent = await getIntentById(surreal, intentId);
234→    if (!intent) {
235→      return jsonError("Intent not found", 404);
236→    }
237→
238→    if (intent.status !== "pending_veto") {
239→      return jsonError(`Intent is in '${intent.status}' status, expected 'pending_veto'`, 409);
240→    }
241→
242→    const originalDetails = intent.authorization_details ?? [];
243→    const proposedDetails = body.constrained_authorization_details;
244→
245→    // Validate each proposed action against its original
246→    for (let i = 0; i < proposedDetails.length; i++) {
247→      const original = originalDetails[i];
248→      const proposed = proposedDetails[i];
249→
250→      if (!original) {
251→        return jsonError(`No original authorization_details at index ${i}`, 400);
252→      }
253→
254→      const boundsCheck = validateTighterBounds(original, proposed);
255→      if (!boundsCheck.valid) {
256→        return jsonError(
257→          `Constraint validation failed: ${boundsCheck.violations.join("; ")}`,
258→          400,
259→        );
260→      }
261→    }
262→
263→    // Update intent with tighter constraints and authorize
264→    const record = await updateIntentStatus(surreal, intentId, "authorized", {});
265→    if (!record.ok) {
266→      return jsonError(record.error, 409);
267→    }
268→
269→    // Update the authorization_details with the constrained version
270→    await surreal.query(
271→      "UPDATE $record SET authorization_details = $details;",
272→      {
273→        record: new RecordId("intent", intentId),
274→        details: proposedDetails,
275→      },
276→    );
277→
278→    log.info("intent.constrained", "Intent constrained and authorized by human", {
279→      intentId,
280→      workspaceId,
281→    });
282→
283→    return jsonResponse({
284→      intentId,
285→      status: "authorized",
286→    }, 200);
287→  };
288→
289→  return { handleEvaluate, handleVeto, handleListPending, handleConsent, handleApprove, handleConstrain };
290→}
