 660→export async function listRecentExtractions(input: WorkspaceQueryInput & { cutoff: Date }): Promise<RecentExtractionRow[]> {
 661→  const [rows] = await input.surreal
 662→    .query<[
 663→      Array<{
 664→        id: RecordId<"extraction_relation", string>;
 665→        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
 666→        out: RecordId<string, string>;
 667→        confidence: number;
 668→        extracted_at: string | Date;
 669→      }>,
 670→    ]>(
 671→      [
 672→        "SELECT id, `in`, out, confidence, extracted_at",
 673→        "FROM extraction_relation",
 674→        "WHERE extracted_at > $cutoff",
 675→        "AND (",
 676→        "  `in` IN (",
 677→        "    SELECT VALUE id FROM message",
 678→        "    WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
 679→        "  )",
 680→        "  OR `in` IN (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
 681→        "  OR `in` IN (SELECT VALUE id FROM git_commit WHERE workspace = $workspace)",
 682→        ")",
 683→        "ORDER BY extracted_at DESC",
 684→        "LIMIT $limit;",
 685→      ].join(" "),
 686→      { workspace: input.workspaceRecord, limit: input.limit, cutoff: input.cutoff },
 687→    )
 688→    .collect<[
 689→      Array<{
 690→        id: RecordId<"extraction_relation", string>;
 691→        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
 692→        out: RecordId<string, string>;
 693→        confidence: number;
 694→        extracted_at: string | Date;
 695→      }>,
 696→    ]>();
 697→
 698→  const results: RecentExtractionRow[] = [];
 699→
 700→  for (const row of rows) {
 701→    const entityKind = row.out.table.name;
 702→    const entityName = await readEntityNameByTable(input.surreal, row.out, entityKind);
 703→    if (!entityName) continue;
 704→
 705→    const sourceKind = row.in.table.name === "document_chunk"
 706→      ? "document_chunk"
 707→      : row.in.table.name === "git_commit"
 708→        ? "git_commit"
 709→        : "message";
 710→
 711→    results.push({
 712→      edgeId: toRecordIdString(row.id),
 713→      sourceKind: sourceKind as "message" | "document_chunk" | "git_commit",
 714→      sourceId: toRecordIdString(row.in),
 715→      entityId: toRecordIdString(row.out),
 716→      entityKind,
 717→      entityName,
 718→      confidence: row.confidence,
 719→      extractedAt: toIso(row.extracted_at),
 720→    });
 721→  }
 722→
 723→  return results;
 724→}
