 991→async function readEntityNameByTable(
 992→  surreal: Surreal,
 993→  record: RecordId<string, string>,
 994→  table: string,
 995→): Promise<string | undefined> {
 996→  if (table === "workspace" || table === "project" || table === "person" || table === "feature") {
 997→    const row = await surreal.select<{ name: string }>(record);
 998→    return row?.name;
 999→  }
1000→
1001→  if (table === "task") {
1002→    const row = await surreal.select<{ title: string }>(record);
1003→    return row?.title;
1004→  }
1005→
1006→  if (table === "decision") {
1007→    const row = await surreal.select<{ summary: string }>(record);
1008→    return row?.summary;
1009→  }
1010→
1011→  if (table === "question") {
1012→    const row = await surreal.select<{ text: string }>(record);
1013→    return row?.text;
1014→  }
1015→
1016→  if (table === "policy") {
1017→    const row = await surreal.select<{ title: string }>(record);
1018→    return row?.title;
1019→  }
1020→
1021→  if (table === "intent") {
1022→    const row = await surreal.select<{ goal: string }>(record);
1023→    return row?.goal;
1024→  }
1025→
1026→  return undefined;
1027→}
