  1→/**
  2→ * Create Intent Handler -- Effect boundary for brain-native create_intent tool
  3→ *
  4→ * Handles the agent self-escalation flow:
  5→ *   1. Parse and validate input arguments
  6→ *   2. Derive authorization_details from action_spec
  7→ *   3. Create intent record in SurrealDB (draft)
  8→ *   4. Evaluate through policy gate
  9→ *   5. If denied: transition to vetoed (no gates edge)
 10→ *   6. If approved: transition to authorized, create gates edge
 11→ *   7. Return CreateIntentOutcome
 12→ *
 13→ * Effect boundary: performs IO (SurrealDB writes, policy gate evaluation).
 14→ * Pure derivation logic (authorization_details) is inline and testable.
 15→ */
 16→import { RecordId, type Surreal } from "surrealdb";
 17→import type { ActionSpec } from "../intent/types";
 18→import type { BrainAction } from "../oauth/types";
 19→import {
 20→  createIntent,
 21→  createTrace,
 22→  updateIntentStatus,
 23→} from "../intent/intent-queries";
 24→import { evaluatePolicyGate } from "../policy/policy-gate";
 25→import { log } from "../telemetry/logger";
 26→
 27→// ---------------------------------------------------------------------------
 28→// Types
 29→// ---------------------------------------------------------------------------
 30→
 31→export type CreateIntentInput = {
 32→  readonly goal: string;
 33→  readonly reasoning: string;
 34→  readonly action_spec: {
 35→    readonly provider: string;
 36→    readonly action: string;
 37→    readonly params?: Record<string, unknown>;
 38→  };
 39→};
 40→
 41→export type CreateIntentOutcome =
 42→  | { readonly status: "authorized"; readonly intentId: string }
 43→  | { readonly status: "pending_veto"; readonly intentId: string }
 44→  | { readonly status: "vetoed"; readonly intentId: string; readonly reason: string }
 45→  | { readonly status: "error"; readonly reason: string };
 46→
 47→export type CreateIntentContext = {
 48→  readonly workspaceId: string;
 49→  readonly identityId: string;
 50→  readonly sessionId: string;
 51→};
 52→
 53→// ---------------------------------------------------------------------------
 54→// Pure: derive authorization_details from action_spec
 55→// ---------------------------------------------------------------------------
 56→
 57→export function deriveAuthorizationDetails(
 58→  actionSpec: CreateIntentInput["action_spec"],
 59→): BrainAction[] {
 60→  return [
 61→    {
 62→      type: "brain_action",
 63→      action: "execute",
 64→      resource: `mcp_tool:${actionSpec.provider}:${actionSpec.action}`,
 65→    },
 66→  ];
 67→}
 68→
 69→// ---------------------------------------------------------------------------
 70→// Input validation (pure)
 71→// ---------------------------------------------------------------------------
 72→
 73→function validateInput(
 74→  args: Record<string, unknown>,
 75→): CreateIntentInput | { error: string } {
 76→  const goal = args.goal;
 77→  const reasoning = args.reasoning;
 78→  const actionSpec = args.action_spec as
 79→    | { provider?: string; action?: string; params?: Record<string, unknown> }
 80→    | undefined;
 81→
 82→  if (typeof goal !== "string" || goal.trim().length === 0) {
 83→    return { error: "Missing or empty 'goal' argument" };
 84→  }
 85→
 86→  if (typeof reasoning !== "string" || reasoning.trim().length === 0) {
 87→    return { error: "Missing or empty 'reasoning' argument" };
 88→  }
 89→
 90→  if (!actionSpec || typeof actionSpec !== "object") {
 91→    return { error: "Missing 'action_spec' argument" };
 92→  }
 93→
 94→  if (typeof actionSpec.provider !== "string" || actionSpec.provider.trim().length === 0) {
 95→    return { error: "Missing or empty 'action_spec.provider'" };
 96→  }
 97→
 98→  if (typeof actionSpec.action !== "string" || actionSpec.action.trim().length === 0) {
 99→    return { error: "Missing or empty 'action_spec.action'" };
100→  }
101→
102→  return {
103→    goal: goal.trim(),
104→    reasoning: reasoning.trim(),
105→    action_spec: {
106→      provider: actionSpec.provider.trim(),
107→      action: actionSpec.action.trim(),
108→      params: actionSpec.params,
109→    },
110→  };
111→}
112→
113→// ---------------------------------------------------------------------------
114→// Handler (effect boundary)
115→// ---------------------------------------------------------------------------
116→
117→/**
118→ * Handle a create_intent brain-native tool call.
119→ *
120→ * Pipeline:
121→ *   validate input -> derive auth details -> create trace -> create intent (draft)
122→ *   -> transition to pending_auth -> evaluate policy gate
123→ *   -> if denied: transition to vetoed (no gates edge)
124→ *   -> if approved: transition to authorized -> create gates edge
125→ *   -> return outcome
126→ */
127→export async function handleCreateIntent(
128→  args: Record<string, unknown>,
129→  context: CreateIntentContext,
130→  surreal: Surreal,
131→): Promise<CreateIntentOutcome> {
132→  // 1. Validate input
133→  const parsed = validateInput(args);
134→  if ("error" in parsed) {
135→    return { status: "error", reason: parsed.error };
136→  }
137→
138→  // 2. Derive authorization_details
139→  const authorizationDetails = deriveAuthorizationDetails(parsed.action_spec);
140→
141→  // 3. Create trace record
142→  const traceRecord = await createTrace(surreal, {
143→    type: "intent_submission",
144→    actor: new RecordId("identity", context.identityId),
145→    workspace: new RecordId("workspace", context.workspaceId),
146→    session: new RecordId("agent_session", context.sessionId),
147→    tool_name: "create_intent",
148→    input: args,
149→  });
150→
151→  // 4. Create intent record (draft)
152→  const actionSpec: ActionSpec = {
153→    provider: parsed.action_spec.provider,
154→    action: parsed.action_spec.action,
155→    params: parsed.action_spec.params ?? {},
156→  };
157→
158→  const intentRecord = await createIntent(surreal, {
159→    goal: parsed.goal,
160→    reasoning: parsed.reasoning,
161→    priority: 50,
162→    action_spec: actionSpec,
163→    trace_id: traceRecord,
164→    requester: new RecordId("identity", context.identityId),
165→    workspace: new RecordId("workspace", context.workspaceId),
166→    authorization_details: authorizationDetails,
167→  });
168→
169→  const intentId = intentRecord.id as string;
170→
171→  // 5. Transition draft -> pending_auth
172→  const toPendingAuth = await updateIntentStatus(surreal, intentId, "pending_auth");
173→  if (!toPendingAuth.ok) {
174→    log.error("create_intent.transition_failed", "Failed to transition intent to pending_auth", {
175→      intent_id: intentId,
176→      error: toPendingAuth.error,
177→    });
178→    return { status: "error", reason: `Intent transition failed: ${toPendingAuth.error}` };
179→  }
180→
181→  // 6. Evaluate policy gate
182→  const identityRecord = new RecordId("identity", context.identityId);
183→  const workspaceRecord = new RecordId("workspace", context.workspaceId);
184→
185→  const policyResult = await evaluatePolicyGate(
186→    surreal,
187→    identityRecord,
188→    workspaceRecord,
189→    {
190→      goal: parsed.goal,
191→      reasoning: parsed.reasoning,
192→      priority: 50,
193→      action_spec: actionSpec,
194→      requester_type: "agent",
195→    },
196→  );
197→
198→  // 7. If policy denies: transition to vetoed, no gates edge
199→  if (!policyResult.passed) {
200→    const toVetoed = await updateIntentStatus(surreal, intentId, "vetoed", {
201→      veto_reason: policyResult.reason,
202→    });
203→
204→    if (!toVetoed.ok) {
205→      log.error("create_intent.transition_failed", "Failed to transition intent to vetoed", {
206→        intent_id: intentId,
207→        error: toVetoed.error,
208→      });
209→      return { status: "error", reason: `Intent transition failed: ${toVetoed.error}` };
210→    }
211→
212→    log.info("create_intent.vetoed", "Intent denied by policy gate", {
213→      intent_id: intentId,
214→      workspace_id: context.workspaceId,
215→      action: `${actionSpec.provider}:${actionSpec.action}`,
216→      deny_rule_id: policyResult.deny_rule_id,
217→    });
218→
219→    return { status: "vetoed", intentId, reason: policyResult.reason };
220→  }
221→
222→  // 8. Policy passed but human veto required: transition to pending_veto, create gates edge
223→  if (policyResult.human_veto_required) {
224→    const toPendingVeto = await updateIntentStatus(surreal, intentId, "pending_veto");
225→    if (!toPendingVeto.ok) {
226→      log.error("create_intent.transition_failed", "Failed to transition intent to pending_veto", {
227→        intent_id: intentId,
228→        error: toPendingVeto.error,
229→      });
230→      return { status: "error", reason: `Intent transition failed: ${toPendingVeto.error}` };
231→    }
232→
233→    // Create gates edge: intent -> gates -> session (needed for scope computation after approval)
234→    const sessionRecordForVeto = new RecordId("agent_session", context.sessionId);
235→    await surreal.query(
236→      `RELATE $intent->gates->$sess SET created_at = time::now();`,
237→      { intent: intentRecord, sess: sessionRecordForVeto },
238→    );
239→
240→    log.info("create_intent.pending_veto", "Intent requires human veto review", {
241→      intent_id: intentId,
242→      session_id: context.sessionId,
243→      workspace_id: context.workspaceId,
244→      action: `${actionSpec.provider}:${actionSpec.action}`,
245→    });
246→
247→    return { status: "pending_veto", intentId };
248→  }
249→
250→  // 9. Policy passed, no veto required: transition pending_auth -> authorized
251→  const toAuthorized = await updateIntentStatus(surreal, intentId, "authorized", {
252→    evaluation: {
253→      decision: "APPROVE",
254→      risk_score: 0,
255→      reason: "Auto-approved: no blocking policy",
256→      evaluated_at: new Date(),
257→      policy_only: true,
258→    },
259→  });
260→
261→  if (!toAuthorized.ok) {
262→    log.error("create_intent.transition_failed", "Failed to transition intent to authorized", {
263→      intent_id: intentId,
264→      error: toAuthorized.error,
265→    });
266→    return { status: "error", reason: `Intent transition failed: ${toAuthorized.error}` };
267→  }
268→
269→  // 9. Create gates edge: intent -> gates -> session
270→  const sessionRecord = new RecordId("agent_session", context.sessionId);
271→  await surreal.query(
272→    `RELATE $intent->gates->$sess SET created_at = time::now();`,
273→    { intent: intentRecord, sess: sessionRecord },
274→  );
275→
276→  log.info("create_intent.authorized", "Intent auto-approved and gates edge created", {
277→    intent_id: intentId,
278→    session_id: context.sessionId,
279→    workspace_id: context.workspaceId,
280→    action: `${actionSpec.provider}:${actionSpec.action}`,
281→  });
282→
283→  return { status: "authorized", intentId };
284→}
