 63→/**
 64→ * Split SQL into statements respecting `{...}` block nesting.
 65→ * DEFINE FUNCTION / DEFINE EVENT bodies contain semicolons that are NOT
 66→ * statement terminators. Naively splitting on `;` breaks those bodies into
 67→ * orphaned fragments that corrupt the batch query.
 68→ */
 69→function splitSqlStatements(sql: string): string[] {
 70→  const stmts: string[] = [];
 71→  let current = "";
 72→  let depth = 0;
 73→  for (let i = 0; i < sql.length; i++) {
 74→    const ch = sql[i];
 75→    if (ch === "{") depth++;
 76→    else if (ch === "}") depth--;
 77→
 78→    if (ch === ";" && depth === 0) {
 79→      const trimmed = current.trim();
 80→      if (trimmed.length > 0) stmts.push(trimmed);
 81→      current = "";
 82→    } else {
 83→      current += ch;
 84→    }
 85→  }
 86→  const trimmed = current.trim();
 87→  if (trimmed.length > 0) stmts.push(trimmed);
 88→  return stmts;
 89→}
 90→
 91→/**
 92→ * Apply the base schema to a SurrealDB instance.
 93→ *
 94→ * DEFINE ANALYZER cannot run inside a transaction in SurrealDB v3.0+.
 95→ * The SDK may treat a multi-statement .query() as an implicit transaction,
 96→ * causing the analyzer and dependent FULLTEXT indexes to fail silently.
 97→ *
 98→ * We split the schema into three phases:
 99→ * 1. DEFINE ANALYZER (must run outside any transaction)
100→ * 2. Schema definitions (DEFINE TABLE/FIELD/INDEX) — batch is fine

