 97→};
 98→
 99→// ---------------------------------------------------------------------------
100→// Domain Helpers -- Business Language Layer
101→// ---------------------------------------------------------------------------
102→
103→/**
104→ * Creates a draft intent directly in the database.
105→ * Used as a Given-step precondition for scenarios that start
106→ * with an intent already in draft status.
107→ */
108→export async function createDraftIntent(
109→  surreal: Surreal,
110→  workspaceId: string,
111→  requesterId: string,
112→  opts: CreateIntentOptions,
113→): Promise<{ intentId: string; intentRecord: RecordId<"intent"> }> {
114→  const result = await createIntentDirectly(surreal, workspaceId, requesterId, {
115→    goal: opts.goal,
116→    reasoning: opts.reasoning,
117→    status: "draft",
118→    priority: opts.priority,
119→    actionSpec: opts.action_spec,
120→    budgetLimit: opts.budget_limit,
121→    taskId: opts.taskId,
122→  });
123→  return { intentId: result.intentId, intentRecord: result.intentRecord };
124→}
125→
126→/**
127→ * Submits a draft intent for authorization.
128→ * Transitions draft -> pending_auth, which triggers the SurrealQL EVENT.
129→ */
130→export async function submitIntent(
131→  surreal: Surreal,
132→  intentId: string,
133→): Promise<void> {
134→  const intentRecord = new RecordId("intent", intentId);
135→  await surreal.query(
136→    `UPDATE $intent SET status = "pending_auth", updated_at = time::now();`,
137→    { intent: intentRecord },
138→  );
139→}
140→
141→/**
142→ * Queries the current status of an intent from the database.
143→ */
144→export async function getIntentStatus(
145→  surreal: Surreal,
146→  intentId: string,
147→): Promise<IntentStatus> {
148→  const intentRecord = new RecordId("intent", intentId);
149→  const rows = (await surreal.query(`SELECT status FROM $intent;`, {
150→    intent: intentRecord,
151→  })) as Array<Array<{ status: IntentStatus }>>;
152→  const result = rows[0]?.[0];
153→  if (!result) {
154→    throw new Error(`Intent ${intentId} not found`);
155→  }
156→  return result.status;
157→}
158→
159→/**
160→ * Queries the full intent record from the database.
161→ */
162→export async function getIntentRecord(
163→  surreal: Surreal,
164→  intentId: string,
165→): Promise<IntentRecord> {
166→  const intentRecord = new RecordId("intent", intentId);
167→  const rows = (await surreal.query(`SELECT * FROM $intent;`, {
168→    intent: intentRecord,
169→  })) as Array<Array<IntentRecord>>;
170→  const result = rows[0]?.[0];
171→  if (!result) {
172→    throw new Error(`Intent ${intentId} not found`);
173→  }
174→  return result;
175→}
176→
177→/**
178→ * Queries the evaluation result for an intent.
179→ */
180→export async function getIntentEvaluation(
181→  surreal: Surreal,
182→  intentId: string,
183→): Promise<EvaluationResult | undefined> {
184→  const record = await getIntentRecord(surreal, intentId);
185→  return record.evaluation;
186→}
