188→/**
189→ * Human vetoes an intent within the veto window.
190→ * Exercises the driving port: POST /api/intents/:id/veto
191→ */
192→export async function vetoIntent(
193→  baseUrl: string,
194→  user: TestUser | TestUserWithToken,
195→  workspaceId: string,
196→  intentId: string,
197→  reason: string,
198→): Promise<{ vetoed: boolean }> {
199→  return fetchJson<{ vetoed: boolean }>(
200→    `${baseUrl}/api/workspaces/${workspaceId}/intents/${intentId}/veto`,
201→    {
202→      method: "POST",
203→      headers: { "Content-Type": "application/json", ...user.headers },
204→      body: JSON.stringify({ reason }),
205→    },
206→  );
207→}
208→
209→/**
210→ * Lists intents in the governance feed that are pending human review.
211→ */
212→export async function listPendingIntents(
213→  surreal: Surreal,
214→  workspaceId: string,
215→): Promise<IntentRecord[]> {
216→  const workspaceRecord = new RecordId("workspace", workspaceId);
217→  const rows = (await surreal.query(
218→    `SELECT * FROM intent
219→     WHERE workspace = $ws AND status IN ["pending_veto"]
220→     ORDER BY priority DESC, created_at ASC;`,
221→    { ws: workspaceRecord },
222→  )) as Array<IntentRecord[]>;
223→  return rows[0] ?? [];
224→}
