398→/**
399→ * Wires the SurrealQL EVENT that fires when an intent transitions to
400→ * pending_auth. The EVENT calls http::post to the real test server's
401→ * evaluate endpoint, enabling true E2E testing of the async evaluation flow.
402→ *
403→ * Callback host can be overridden via INTENT_EVAL_CALLBACK_HOST.
404→ * Call this in beforeAll after the test server has booted.
405→ */
406→export async function wireIntentEvaluationEvent(
407→  surreal: Surreal,
408→  port: number,
409→): Promise<void> {
410→  const configuredHost = process.env.INTENT_EVAL_CALLBACK_HOST?.trim();
411→  const candidateHosts = configuredHost && configuredHost.length > 0
412→    ? [configuredHost]
413→    : ["127.0.0.1", "host.docker.internal"];
414→
415→  let baseUrl: string | undefined;
416→  let lastError = "";
417→
418→  for (const host of candidateHosts) {
419→    const candidateBaseUrl = `http://${host}:${port}`;
420→
421→    try {
422→      await surreal.query(`RETURN http::head($url);`, {
423→        url: `${candidateBaseUrl}/healthz`,
424→      });
425→      baseUrl = candidateBaseUrl;
426→      break;
427→    } catch (error) {
428→      lastError = error instanceof Error ? error.message : String(error);
429→    }
430→  }
431→
432→  if (!baseUrl) {
433→    throw new Error(
434→      `Unable to reach acceptance server from SurrealDB for intent callback. ` +
435→      `Tried hosts: ${candidateHosts.join(", ")} on port ${port}. ` +
436→      `Last error: ${lastError}`,
437→    );
438→  }
439→
440→  await surreal.query(`
441→    DEFINE EVENT OVERWRITE intent_pending_auth ON intent
442→      ASYNC
443→      RETRY 3
444→      WHEN $before.status != "pending_auth" AND $after.status = "pending_auth"
445→      THEN {
446→        http::post("${baseUrl}/api/intents/" + <string> meta::id($after.id) + "/evaluate", $after)
447→      };
448→  `);
449→}
