 64→    {
 65→      workspace: workspaceRecord,
 66→      content: {
 67→        name: opts?.workspaceName ?? `Test Workspace ${suffix}`,
 68→        status: "active",
 69→        onboarding_complete: true,
 70→        onboarding_turn_count: 0,
 71→        onboarding_summary_pending: false,
 72→        onboarding_started_at: new Date(),
 73→        created_at: new Date(),
 74→        ...(opts?.repoPath ? { repo_path: opts.repoPath } : {}),
 75→      },
 76→    },
 77→  );
 78→
 79→  await surreal.query(
 80→    `CREATE $identity CONTENT $content;`,
 81→    {
 82→      identity: identityRecord,
 83→      content: {
 84→        name: opts?.identityName ?? `Test User ${suffix}`,
